      function CF_PAYMENT_AMOUNTFormula return Number is

v_calc_begin_date_varchar varchar2(10);
v_calc_begin_date date;
V_AMOUNT NUMBER;

begin

	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00318','00420');
		IF v_calc_begin_date_varchar IS NOT NULL THEN
		   v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
		END IF;


	V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
																													 ,NULL
																													 ,v_calc_begin_date
																												 	 ,:P_ACC_START_DATE
																													 ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+:P_PENSION_AMOUNT); 
  
  
end;

      function CF_AWARD_PROMPTFormula return Char is

V_AWARD_FLAG VARCHAR2(1);
V_PROMPT     VARCHAR2(100);

Cursor cur_award_prompt Is
 SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DEC_INCR_SEC_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

cursor Find_Conv_account is
SELECT pen_dec_fact_types_instance.VALUE
FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00318' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00341' 
;

cursor find_conv_decision(v_account_no number) is
Select A.Dt_Dec_Unit_Code||'/'||A.Dt_Decision_Year||'/'||A.Dec_Incr_Seq_No||'-'||TO_CHAR(A.LAST_PRINT_TIME_DEC, 'DD/MM/RRRR')
--ALKA 17012014 A.Payment_Start_Date
From Pen_Decision_Instance A,
     Pen_Account B
Where A.Document_Type_Dec_Code_Sr =B.Di_Dt_Document_Type_Dec_Code
And A.Dec_Unit_Code_Sr=B.Di_Dt_Dec_Unit_Code
And A.Decision_Year_Sr=B.Di_Dt_Decision_Year
And A.Incr_Seq_No_Sr=B.Di_Dec_Incr_Seq_No
And B.Account_No =v_account_no
;
v_conv_account number;
v_conv_decision varchar2(50);

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 :CP_AWARD_TYPE:=V_AWARD_FLAG;
 IF V_AWARD_FLAG IN ('0','1','2') THEN
 	  V_PROMPT:='Απονομής';
 ELSIF V_AWARD_FLAG IN ('3','4') THEN
 	    V_PROMPT:='Παράτασης';
 ELSIF V_AWARD_FLAG IN ('8') THEN
 	   open Find_Conv_account;
 	  fetch Find_Conv_account into v_conv_account;
 	  close Find_Conv_account;
 	  open find_conv_decision(v_conv_account);
 	  fetch find_conv_decision into v_conv_decision;
 	  close find_conv_decision;
 	  :CP_CONV_DECISION:=v_conv_decision;
 	  V_PROMPT:='( απόφαση:'||v_conv_decision||' )';--'τροποποίησης της απόφασης';
 	END IF;
 
 RETURN V_PROMPT;
 
end;

      function CF_AWARD_PROMPT2Formula return Char is
V_AWARD_FLAG VARCHAR2(1);
V_PROMPT     VARCHAR2(1000);

my_descr_kind_pension   varchar2(30);
my_left_bra							varchar(1);
my_right_bra							varchar(1);
my_kind_disability			varchar2(100);
my_dash									varchar(1);	
my_Disability_Reason		varchar2(100);	
v_percent 	NUMBER;
my_text1  	VARCHAR2(100);
--my_days			number;
v_boolean   boolean;
V_Psycho		number;
V_DEDUCT    VARCHAR2(1);
my_text2  	VARCHAR2(100);
V_PROCUCT_CODE NUMBER;


Cursor cur_award_prompt Is
 SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DEC_INCR_SEC_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

Cursor cur_Kind_pension_descr is
SELECT PEN_PRODUCTS.PROCUCT_DESCRIPTION, 
       PEN_PRODUCTS.PRODUCT_CODE
FROM PEN_ACCOUNT, 
     PEN_PRODUCTS, 
	 PEN_PRODUCT_PER_INSTITUTIONS,
	 PEN_QUALIFYING_SUBTERMS, 
	 PEN_QC_PER_PRODINST,
	 PEN_DECISION_INSTANCE
WHERE PEN_ACCOUNT.ACCOUNT_NO=:P_ACC_ACCOUNT_NO
AND PEN_ACCOUNT.QCPRODINS_QC_PER_PRODINST_CODE=PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE
AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
AND PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE=PEN_PRODUCTS.PRODUCT_CODE
AND PEN_ACCOUNT.QUALIFYING_SUBTERM_CODE=PEN_QUALIFYING_SUBTERMS.QUALIFYING_SUBTERM_CODE
AND PEN_DECISION_INSTANCE.INS_INSURED_ID= PEN_ACCOUNT.INS_INSURED_ID
AND PEN_DECISION_INSTANCE.DOCUMENT_TYPE_DEC_CODE_SR=PEN_ACCOUNT.DI_DT_DOCUMENT_TYPE_DEC_CODE
AND PEN_DECISION_INSTANCE.INCR_SEQ_NO_SR=PEN_ACCOUNT.DI_DEC_INCR_SEQ_NO
AND PEN_DECISION_INSTANCE.DECISION_YEAR_SR=PEN_ACCOUNT.DI_DT_DECISION_YEAR
AND PEN_DECISION_INSTANCE.DEC_UNIT_CODE_SR=PEN_ACCOUNT.DI_DT_DEC_UNIT_CODE;
--AND PEN_DECISION_INSTANCE.DEC_INCR_SEQ_NO=:P_DEC_INCR_SEC_NO;


Cursor Cur_kind_disability is
SELECT PEN_DISABILITY_TYPES.DISABILITY_TYPE_DESCR 
FROM pen_dec_fact_types_instance, PEN_DISABILITY_TYPES
WHERE pen_dec_fact_types_instance.title_code IN ('00149') AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00276'
AND PEN_DISABILITY_TYPES.DISABILITY_TYPE_CODE=pen_dec_fact_types_instance.VALUE;

Cursor Cur_Disability_Reason is
SELECT PEN_DEATH_REASON.REASON_DESCR FROM pen_dec_fact_types_instance, PEN_DEATH_REASON	 
WHERE pen_dec_fact_types_instance.title_code='00149' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00209' AND 
pen_dec_fact_types_instance.VALUE=PEN_DEATH_REASON.REASON_CODE;



Cursor cur_deduct Is
 SELECT B.DEDUCT_FLG
FROM PEN_ACCOUNT A,
     PEN_QUALIFYING_SUBTERMS B
WHERE A.QUALIFYING_SUBTERM_CODE = B.QUALIFYING_SUBTERM_CODE
AND   A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


	
begin
	
 OPEN cur_deduct;
   FETCH cur_deduct 
   INTO V_deduct;
 CLOSE cur_deduct;
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 
  OPEN cur_Kind_pension_descr;
   FETCH cur_Kind_pension_descr 
   INTO my_descr_kind_pension,
        V_PROCUCT_CODE;
 CLOSE cur_Kind_pension_descr;
 
 OPEN Cur_kind_disability;
   FETCH Cur_kind_disability 
   INTO my_kind_disability;
 CLOSE Cur_kind_disability;
                           

OPEN Cur_Disability_Reason;
   FETCH Cur_Disability_Reason 
   INTO my_Disability_Reason;
 CLOSE Cur_Disability_Reason;                           

                           

 IF :P_PRODINST not IN (8,51,1,2,1204,211,212) THEN
  	my_text1:='';
  ELSE
  	
  


/*	select total_days
	into 		my_days  
	from 		pen_account_rep
	where account_no=:p_acc_account_no;
	*/

v_percent := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                         :P_DT_DECISION_YEAR,
                                         :P_DT_DEC_UNIT_CODE,
                                         :P_DEC_INCR_SEC_NO_SR, 
                                         '1',
			                                   0,
			                                   :p_form_id,
			                                   '00001',
			                                   '00035',
			                                   '00200');
			                                   

	  	
		V_Psycho := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
																						:P_DT_DECISION_YEAR,
																						:P_DT_DEC_UNIT_CODE,
																						:P_DEC_INCR_SEC_NO_SR,
																						'1',
	               				        						0,
	               				        						:p_form_id,
	               				        						'00001',
	               				        						'00035',
	               				        						'00261');

IF v_percent IS NULL
		OR (v_percent = 75 AND (:p_total_days) >= 6000 AND (V_Psycho!='1' OR V_Psycho IS NULL) ) THEN
			v_percent := 100;
--ELSIF (v_percent = 50 AND (:p_total_days) >= 6000 AND (V_Psycho!='1' OR V_Psycho IS NULL) ) THEN
--        v_percent := 75;
END IF;	               				        						

			                                   


if v_percent= 100 then
	 	my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
elsif v_percent= 75 then
		my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΟ 75% ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
else
		my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΟ 50% ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
end if;


if nvl(v_deduct,0) != 0 then
	 	my_text2:='ΜΕΙΩΜΕΝΗ';
else
		my_text2:='ΠΛΗΡΗ';
end if;


END IF;
 
 
 
 begin
  if :p_prodinst IN (8,51,1204)  then
  	select '(',')' into my_left_bra,my_right_bra from dual;
  else
  	my_left_bra:=null;
  	my_right_bra:=null;
  end if;
 end;
 
 begin
  if :p_prodinst in (8,51,1204) then
  	select '-' into my_dash from dual;
  else
  	my_dash:=null;
  end if;
end;
 
 
 
 IF V_PROCUCT_CODE='00002' THEN
 IF V_AWARD_FLAG IN ('0','1','2') THEN
 	  V_PROMPT:='ΑΠΟΝΕΜΟΥΜΕ '||my_descr_kind_pension||' '||my_left_bra||' '||my_kind_disability||' '||my_dash||' '||my_Disability_Reason||' '||my_right_bra||' '||chr(10)||'ΣΥΜΦΩΝΑ ΜΕ ΤΙΣ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘ.:';
 ELSE 
 	  V_PROMPT:='ΧΟΡΗΓΟΥΜΕ '||my_descr_kind_pension||' '||my_left_bra||' '||my_kind_disability||' '||my_dash||' '||my_Disability_Reason||' '||my_right_bra||' '||chr(10)||'ΣΥΜΦΩΝΑ ΜΕ ΤΙΣ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘ.:';
 	END IF;
 
 ELSIF V_PROCUCT_CODE='00001' THEN
  IF V_AWARD_FLAG IN ('0','1','2') THEN
 	  V_PROMPT:='ΑΠΟΝΕΜΟΥΜΕ '||my_descr_kind_pension||' '||my_text2||chr(10)||'ΣΥΜΦΩΝΑ ΜΕ ΤΙΣ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘ.:';
 ELSE 
 	  V_PROMPT:='ΧΟΡΗΓΟΥΜΕ '||my_descr_kind_pension||' '||my_text2||chr(10)||'ΣΥΜΦΩΝΑ ΜΕ ΤΙΣ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘ.:';
 	END IF;
 
 END IF;
 
 RETURN V_PROMPT;
 

 
END;

