  		fetch cur_limit_amnt
  		into v_limit_amount_for_excess,
  				 v_number_of_HAE,
  				 V_Single_Wages_Triennium0;
  		close cur_limit_amnt;
  		V:= 'ΣΤΟ ΠΟΣΟ ΠΟΥ ΥΠΕΡΒΑΙΝΕΙ ΤΑ '||v_number_of_HAE||'ΗΑΕ x'||V_Single_Wages_Triennium0||'='||v_limit_amount_for_excess||' ΕΥΡΩ';	  		
  	ELSIF :SECTOR = 'Δ' THEN
  		V := 'ΣΤΟ ΣΥΝΟΛΙΚΟ ΠΟΣΟ ΤΗΣ ΣΥΝΤΑΞΗΣ';  	
  	END IF;
  	
  ELSE 
  	V := :DECODE_WORK_INS_SECTOR_Ι_ΣΤΟ_Π;
  END IF;
  
  RETURN V;
  
end;

