lc3 Number;


cursor c_wrk is 
select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid 
from wrk_decisions a
where a.status   = '1'
and   a.pen_unit = :P_DT_DEC_UNIT_CODE
and   a.pen_year = :P_DT_DECISION_YEAR
and   a.pen_no   = :P_DEC_INCR_SEC_NO
;

begin
  open c1; 
	 fetch c1 into :p_branch_name, :p_branch_code, :P_PRODUCT_CODE;
	close c1; 
	
	open c2; 
	 fetch c2 into l_pollapli_syntaxi;
	close c2; 
	
	open c3; 
	 fetch c3 into lc3;
	close c3; 
	
	if nvl(lc3,0) >= 1 
	  then :p_application_efka_days := 1;
	  else :p_application_efka_days := 0;
	end if; 
	  
	if :p_branch_code = '00054' then
  	if :p_commit_date <= to_date('18/06/2020','dd/mm/yyyy') then 
  		 :p_branch_name := 'ΠΕΡΙΦΕΡΕΙΑΚΗ ΔΙΕΥΘΥΝΣΗ ΣΥΝΤΑΞΕΩΝ Ν.Π.Δ.Δ.';                                                                      
  	elsif :p_commit_date >= to_date('19/06/2020','dd/mm/yyyy') then 	
  		 :p_branch_name    := 'Β''''Δ/ΝΣΗ ΑΠΟΝΟΜΗΣ ΣΥΝΤΑΞΕΩΝ & ΕΦΑΠΑΞ ΔΗΜΟΣΙΟΥ ΤΟΜΕΑ';
  		 :P_BRANCH_2_00054 := 'Tμήμα:Α''''ΤΜ. ΑΠΟΝΟΜΗΣ ΚΥΡΙΑΣ ΣΥΝΤΑΞΗΣ, ΕΠΙΚΟΥΡΙΚΗΣ & ΕΦΑΠΑΞ ΠΑΡΟΧΗΣ - ΝΠΔΔ' ;  
  	end if;	  
	end if; 
	
  
  if nvl(l_pollapli_syntaxi,'0') = '1' 
  	then 
  	:P_POLLAPLI_SYNTAXI := 1;
  else
    :P_POLLAPLI_SYNTAXI := 0;
  end if;
  
  open c_wrk;
	 fetch c_wrk into :P_WRK_DEC_NO;
	close c_wrk;
	
  -- ΕΡΓΑΣΙΑ ΜΕΤΑ ΤΟ 2024
  :P_ERGASIA_2024 := CHECK_ERGASIA_2024(:P_INSURED_ID,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR);
	
  return (TRUE);
  
end;

