      function F_225FormatTrigger return boolean is
V_STRING VARCHAR2(500);

begin
  V_STRING :=   :DECODED_SEX ||'με τα κάτωθι στοιχεία:' ||CHR(10) || chr(10)|| 'A.Σ        :'||:P_INSURED_ID||CHR(10)|| 'Ονοματεπώνυμο:'||:FULLNAME||CHR(10)||'Όνομα Πατρός :'||:FATHER_NAME||CHR(10)|| 'Όνομα Μητρός :' ||:MOTHER_NAME||CHR(10)
  ||'ΑΜΚΑ:'||:AMKA_ID|| chr(10)||'Α.Φ.Μ.:'||:CF_AFM|| chr(10);
