      function CF_MAIN_DESCRIPTIONFormula return Char is
V_STRING VARCHAR2(2000);

begin
	
  V_STRING := 'Αίτηση για απονομή σύνταξης '||:CP_PRODUCT_DESC||' με αριθμό πρωτοκόλλου '||:CP_APPLICATION_INSTANCES_PROT ; 

  
  return (V_STRING);
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

