      function CF_53Formula return Char is
begin
	IF :PRODUCT_CODE = '00001'
		THEN :CP_PRODUCT_DESC := 'ΓΗΡΑΤΟΣ';
	ELSIF :PRODUCT_CODE = '00002'
		THEN :CP_PRODUCT_DESC := 'ΑΝΑΠΗΡΙΑΣ';
	ELSE :CP_PRODUCT_DESC := :PROCUCT_DESCRIPTION;
	END IF;
  RETURN ( :CP_PRODUCT_DESC );
end;

